        JI("dup", "");
        JI("getstatic", "java/lang/System/in Ljava/io/InputStream;");
        JI("invokespecial", "java/io/InputStreamReader/<init>(Ljava/io/InputStream;)V");
        JI("invokespecial", "java/io/BufferedReader/<init>(Ljava/io/Reader;)V");
