        put_int_field(pf);            /* no change — s2.indexOf scans from pf (0-based=pf-1+1=pf) */
        JGoto(chk);
        /* check */
        JL(chk);
        get_str_field(s1f);
        get_str_field(s2f);
        get_int_field(pf);
