        J("    dup2\n    lconst_1\n    lneg\n    lcmp\n    ifne %s\n", ok);
        J("    pop2\n"); JGoto(ports.ω);
        JL(ok);
        JC("find ok: store result as new pos, push result → γ");
        J("    dup2\n    l2i\n"); put_int_field(pf);
