        J("    dup2\n    lconst_1\n    lneg\n    lcmp\n    ifne %s\n", ok);
        J("    pop2\n"); JGoto(ports.ω);
        JL(ok);
        JC("match ok: icn_pos = result-1 (0-based), push result → γ");
        J("    dup2\n    l2i\n    iconst_1\n    isub\n");
        put_int_field("icn_pos");
        JGoto(ports.γ);
        return;
